package main.rice.obj;

import java.util.Set;
import java.util.StringJoiner;

/**
 * Represents a Python set object.
 * @param <T> the type of elements in the set
 */
public class PySetObj<T extends APyObj<?>> extends AIterablePyObj<Set<T>> {

    public PySetObj(Set<T> value) {
        super(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        StringJoiner sj = new StringJoiner(", ", "{", "}");
        for (T elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

/**
 * Represents a Python boolean object (True or False).
 */
public class PyBoolObj extends APyObj<Boolean> {

    public PyBoolObj(Boolean value) {
        super(value);
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }
}

package main.rice.obj;

import java.util.List;
import java.util.StringJoiner;

/**
 * Represents a Python tuple object.
 * @param <T> the type of elements in the tuple
 */
public class PyTupleObj<T extends APyObj<?>> extends AIterablePyObj<List<T>> {

    public PyTupleObj(List<T> value) {
        super(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "()";
        }
        if (value.size() == 1) {
            return "(" + value.get(0).toString() + ",)";
        }
        StringJoiner sj = new StringJoiner(", ", "(", ")");
        for (T elem : value) {
            sj.add(elem.toString());
        }
        return sj.toString();
    }
}

package main.rice.obj;

/**
 * Represents a Python character (single-character string element).
 */
public class PyCharObj extends APyObj<Character> {

    public PyCharObj(Character value) {
        super(value);
    }

    @Override
    public String toString() {
        return value.toString();
    }
}

package main.rice.obj;

import java.util.Map;
import java.util.StringJoiner;

/**
 * Represents a Python dictionary object.
 * @param <K> the type of keys
 * @param <V> the type of values
 */
public class PyDictObj<K extends APyObj<?>, V extends APyObj<?>> extends AIterablePyObj<Map<K, V>> {

    public PyDictObj(Map<K, V> value) {
        super(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "{}";
        }
        StringJoiner sj = new StringJoiner(", ", "{", "}");
        for (Map.Entry<K, V> entry : value.entrySet()) {
            sj.add(entry.getKey().toString() + ": " + entry.getValue().toString());
        }
        return sj.toString();
    }
}

